const functions = require('@google-cloud/functions-framework');
const { BigQuery } = require('@google-cloud/bigquery');

const bigquery = new BigQuery();

functions.http('processLargeDataset', async (req, res) => {
  const dataset = process.env.BQ_DATASET || 'your_dataset';
  const table = process.env.BQ_TABLE || 'your_table';
  const projectId = process.env.BQ_PROJECT || await bigquery.getProjectId();

  const query = `
    SELECT
      category,
      COUNT(*) AS record_count,
      SUM(amount) AS total_amount,
      AVG(amount) AS avg_amount
    FROM \`${projectId}.${dataset}.${table}\`
    GROUP BY category
    ORDER BY total_amount DESC
  `;

  try {
    const [job] = await bigquery.createQueryJob({
      query,
      location: process.env.BQ_LOCATION || 'US',
      useLegacySql: false,
      priority: 'BATCH'
    });

    const [rows] = await job.getQueryResults();

    res.status(200).json({
      success: true,
      jobId: job.id,
      rowCount: rows.length,
      results: rows
    });
  } catch (error) {
    console.error('BigQuery aggregation failed:', error);
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

exports.processLargeDataset = {
  memory: '8GiB',
  timeoutSeconds: 540
};